def maxDepthAfterSplit(self, seq: str) -> List[int]:
    n = len(seq)
    depths = [0] * n
    for i in range(1, n):
        if seq[i] == '(':
            depths[i] = depths[i - 1] + 1
        elif seq[i] == ')':
            depths[i] = depths[i - 1]
    answer = []
    for i in range(n):
        if depths[i] == 0:
            answer.append(0)
        else:
            j = i
            while depths[j] > depths[i]:
                j = max(j - 1, 0)
            answer.append(depths[j])
    return answer

